// Each tip is a function that receives the stock context for personalization
// Usage: tips[index]({ name, ticker, dividend_yield, price, sector, country })
interface TipContext {
  name: string;
  ticker: string;
  dividend_yield: number;
  price: number;
  sector: string;
  country: string;
}

